def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        score = 0.0
        weight_factor = 1.0
        penalty = 0.0
        for j in range(1, 15):
            if j % 3 == 0:
                weight_factor *= 1.05
            elif j % 7 == 0:
                weight_factor *= 0.89
            for m in range(1, 4):
                val = (item * m) / (cap + m)
                if val > 0.5:
                    score += (np.sin(j) + np.tanh(val)) * weight_factor / (m + 1)
                else:
                    penalty += (np.exp(-val * j) + np.log1p(j*m)) * 0.5 / (j + m)
            if ratio > 0.8 and j % 5 == 0:
                score *= 1.1
            elif ratio < 0.3 and j % 4 == 0:
                score *= 0.9
            if cap % (j + 2) == 0:
                score += j * 0.3
            elif (cap + j) % 5 == 0:
                penalty += j * 0.2
            if j == 10:
                for k in range(1, 6):
                    diff = cap - (item * k)
                    if diff > 0:
                        if diff % 3 == 0:
                            score += np.log1p(diff) / (k + 3)
                        else:
                            penalty += (diff ** 0.8) / (k + 1)
                    else:
                        penalty += abs(diff) ** 1.3 / (k + 2)
        combined = score - penalty
        if combined == 0:
            priorities[i] = np.inf
        elif combined < 0:
            priorities[i] = -combined * np.sqrt(cap + item + 1)
        else:
            if cap > item * 3:
                priorities[i] = -combined / (np.cbrt(cap) + 1)
            else:
                priorities[i] = -combined / (cap + 1)
        if ratio > 0.95:
            priorities[i] *= 1.3
        elif ratio < 0.05:
            priorities[i] *= 0.7
        if cap % 2 == 0 and item % 1 < 0.5:
            priorities[i] *= 0.95
        elif cap % 2 != 0 and item % 1 >= 0.5:
            priorities[i] *= 1.05
    return priorities
